import org.jsoup.nodes.Document;

import java.io.IOException;
import java.util.logging.Logger;
import java.util.regex.Pattern;

public class BookmarkService {

    private static final Logger logger = Logger.getLogger(BookmarkService.class.getName());

    private static final int TIMEOUT_MILLIS = 10000;
    private static final int MAX_BODY_SIZE = 1024 * 1024; // 1MB
    private static final String USER_AGENT = "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36";

    private static final Pattern URL_PATTERN = Pattern.compile(
            "^https?://[\\w.-]+(?:\\.[\\w.-]+)+[/#?]?.*$",
            Pattern.CASE_INSENSITIVE
    );

    public String fetchTitleFromUrl(String urlString) throws IOException {
        if (urlString == null || urlString.trim().isEmpty()) {
            logger.warning("URL string is null or empty");
            return null;
        }

        urlString = urlString.trim();

        if (!URL_PATTERN.matcher(urlString).matches()) {
            logger.warning("Invalid URL format: " + urlString);
            return null;
        }

        Document doc = Jsoup.connect(urlString)
                .userAgent(USER_AGENT)
                .timeout(TIMEOUT_MILLIS)
                .maxBodySize(MAX_BODY_SIZE)
                .followRedirects(true)
                .ignoreHttpErrors(true)
                .ignoreContentType(true)
                .get();

        String title = doc.title();

        if (title == null || title.trim().isEmpty()) {
            logger.info("No title found for URL: " + urlString);
            return null;
        }

        return title.trim();
    }
}

