import java.net.UnknownHostException;
import java.util.Arrays;

public class BookmarkService {

    private static final int TIMEOUT_MS = 5000;
    private static final int MAX_BODY_SIZE = 1024 * 1024; // 1MB

    public String fetchTitleFromUrl(String urlString) throws IOException {
        // Validate URL and resolve with security checks
        URL validatedUrl = validateUrl(urlString);

        // Fetch document using Jsoup with security settings
        Document doc = Jsoup.connect(validatedUrl.toString())
                .timeout(TIMEOUT_MS)
                .maxBodySize(MAX_BODY_SIZE)
                .followRedirects(true)
                .ignoreContentType(true)
                .ignoreHttpErrors(false)
                .get();

        return doc.title();
    }

    private URL validateUrl(String urlString) throws IOException {
        if (urlString == null || urlString.trim().isEmpty()) {
            throw new IllegalArgumentException("URL cannot be null or empty");
        }

        // Parse and normalize URL
        URL url;
        try {
            URI uri = new URI(urlString.trim()).normalize();
            url = uri.toURL();
        } catch (URISyntaxException | IllegalArgumentException e) {
            throw new IllegalArgumentException("Invalid URL format: " + e.getMessage());
        }

        // Protocol whitelist - only HTTP and HTTPS allowed
        String protocol = url.getProtocol();
        if (protocol == null || (!"http".equalsIgnoreCase(protocol) && !"https".equalsIgnoreCase(protocol))) {
            throw new IllegalArgumentException("Only HTTP and HTTPS protocols are allowed");
        }

        // Validate host exists
        String host = url.getHost();
        if (host == null || host.isEmpty()) {
            throw new IllegalArgumentException("URL must contain a valid host");
        }

        // Resolve and validate IP address to prevent SSRF
        validateResolvedIpAddress(host);

        return url;
    }

    private void validateResolvedIpAddress(String host) throws IOException {
        InetAddress[] addresses;
        try {
            addresses = InetAddress.getAllByName(host);
        } catch (UnknownHostException e) {
            throw new IOException("Unable to resolve host: " + host);
        }

        // Validate all resolved addresses
        for (InetAddress address : addresses) {
            if (isInternalOrReservedIp(address)) {
                throw new IllegalArgumentException("Access to internal or reserved IP addresses is not allowed");
            }
        }
    }

    private boolean isInternalOrReservedIp(InetAddress address) {
        // Java built-in checks for common cases
        if (address.isLoopbackAddress() ||
            address.isLinkLocalAddress() ||
            address.isSiteLocalAddress() ||
            address.isAnyLocalAddress()) {
            return true;
        }

        byte[] bytes = address.getAddress();

        // IPv4 address checks
        if (bytes.length == 4) {
            return isInternalOrReservedIPv4(bytes);
        }

        // IPv6 address checks
        if (bytes.length == 16) {
            return isInternalOrReservedIPv6(bytes);
        }

        return false;
    }

    private boolean isInternalOrReservedIPv4(byte[] bytes) {
        int first = bytes[0] & 0xFF;
        int second = bytes[1] & 0xFF;
        int third = bytes[2] & 0xFF;
        int fourth = bytes[3] & 0xFF;

        // 0.0.0.0/8 - Current network (only valid as source)
        if (first == 0) return true;

        // 10.0.0.0/8 - Private network
        if (first == 10) return true;

        // 127.0.0.0/8 - Loopback
        if (first == 127) return true;

        // 169.254.0.0/16 - Link-local (includes cloud metadata endpoints like AWS 169.254.169.254)
        if (first == 169 && second == 254) return true;

        // 172.16.0.0/12 - Private network
        if (first == 172 && second >= 16 && second <= 31) return true;

        // 192.0.0.0/24 - IETF Protocol Assignments
        if (first == 192 && second == 0 && third == 0) return true;

        // 192.0.2.0/24 - TEST-NET-1 (documentation)
        if (first == 192 && second == 0 && third == 2) return true;

        // 192.168.0.0/16 - Private network
        if (first == 192 && second == 168) return true;

        // 198.18.0.0/15 - Benchmark testing
        if (first == 198 && (second == 18 || second == 19)) return true;

        // 198.51.100.0/24 - TEST-NET-2 (documentation)
        if (first == 198 && second == 51 && third == 100) return true;

        // 100.64.0.0/10 - Carrier-grade NAT
        if (first == 100 && second >= 64 && second <= 127) return true;

        // 203.0.113.0/24 - TEST-NET-3 (documentation)
        if (first == 203 && second == 0 && third == 113) return true;

        // 224.0.0.0/4 - Multicast
        if (first >= 224 && first <= 239) return true;

        // 240.0.0.0/4 - Reserved for future use
        if (first >= 240) return true;

        // 255.255.255.255 - Limited broadcast
        if (first == 255 && second == 255 && third == 255 && fourth == 255) return true;

        return false;
    }

    private boolean isInternalOrReservedIPv6(byte[] bytes) {
        // ::1 - Loopback
        if (isAllZeros(bytes, 0, 15) && (bytes[15] & 0xFF) == 1) return true;

        // :: - Unspecified address
        if (isAllZeros(bytes, 0, 16)) return true;

        // ::ffff:0:0/96 - IPv4-mapped addresses (check embedded IPv4)
        if (isAllZeros(bytes, 0, 10) && (bytes[10] & 0xFF) == 0xFF && (bytes[11] & 0xFF) == 0xFF) {
            byte[] ipv4Bytes = Arrays.copyOfRange(bytes, 12, 16);
            return isInternalOrReservedIPv4(ipv4Bytes);
        }

        // fc00::/7 - Unique local address
        if ((bytes[0] & 0xFE) == 0xFC) return true;

        // fe80::/10 - Link-local
        if ((bytes[0] & 0xFF) == 0xFE && (bytes[1] & 0xC0) == 0x80) return true;

        // ff00::/8 - Multicast
        if ((bytes[0] & 0xFF) == 0xFF) return true;

        return false;
    }

    private boolean isAllZeros(byte[] bytes, int start, int length) {
        for (int i = start; i < start + length; i++) {
            if (bytes[i] != 0) return false;
        }
        return true;
    }
}

